#include <bits/stdc++.h>
using namespace std;
int main(){int N;cin>>N;vector<long long>a(N);long long mx=0,tot=0;for(auto&x:a){cin>>x;mx=max(mx,x);tot+=x;}long long M;cin>>M;if(tot<=M){cout<<mx<<"\n";return 0;}long long lo=0,hi=mx,ans=0;while(lo<=hi){long long c=(lo+hi)/2,s=0;for(auto x:a)s+=min(x,c);if(s<=M){ans=c;lo=c+1;}else hi=c-1;}cout<<ans<<"\n";}
